class ServiceState:
    """Tracks internal service state for debugging purposes."""

    def __init__(self):
        self.request_count = 0
        self.error_count = 0
        self.last_error = None
        self.last_error_time = None
        self.start_time = datetime.utcnow().isoformat()
        self.active_requests = {}
        self.circuit_breaker_open = False
        self.dependencies = {
            "database": "connected",
            "cache": "connected",
            "payment_gateway": "connected",
            "inventory_service": "connected",
        }

    def to_dict(self):
        return {
            "request_count": self.request_count,
            "error_count": self.error_count,
            "last_error": self.last_error,
            "last_error_time": self.last_error_time,
            "service_start_time": self.start_time,
            "active_requests": len(self.active_requests),
            "active_request_ids": list(self.active_requests.keys()),
            "circuit_breaker_open": self.circuit_breaker_open,
            "dependencies": self.dependencies,
        }

    def register_request(self, request_id, method_name):
        self.request_count += 1
        self.active_requests[request_id] = {
            "method": method_name,
            "start_time": datetime.utcnow().isoformat(),
        }

    def complete_request(self, request_id):
        self.active_requests.pop(request_id, None)

    def register_error(self, error_msg):
        self.error_count += 1
        self.last_error = error_msg
        self.last_error_time = datetime.utcnow().isoformat()


