class ErrorContext:
    """Builds detailed error context for gRPC responses."""

    @staticmethod
    def build_error_details(
        exception: Exception,
        method_name: str,
        request_id: str,
        service_state: ServiceState,
        request_data: dict = None,
        additional_context: dict = None,
    ) -> str:
        """Build comprehensive error details as JSON string."""
        error_details = {
            "error_type": type(exception).__name__,
            "error_message": str(exception),
            "stack_trace": traceback.format_exc(),
            "method_name": method_name,
            "request_id": request_id,
            "timestamp": datetime.utcnow().isoformat(),
            "service_state": service_state.to_dict(),
        }

        if request_data:
            error_details["request_data"] = request_data

        if additional_context:
            error_details["additional_context"] = additional_context

        # Add exception chain info
        cause = exception.__cause__
        if cause:
            error_details["caused_by"] = {
                "error_type": type(cause).__name__,
                "error_message": str(cause),
                "stack_trace": "".join(traceback.format_exception(type(cause), cause, cause.__traceback__)),
            }

        return json.dumps(error_details, indent=2, default=str)

    @staticmethod
    def map_exception_to_grpc_code(exception: Exception) -> grpc.StatusCode:
        """Map Python exceptions to appropriate gRPC status codes."""
        mapping = {
            KeyError: grpc.StatusCode.NOT_FOUND,
            ValueError: grpc.StatusCode.INVALID_ARGUMENT,
            TypeError: grpc.StatusCode.INVALID_ARGUMENT,
            PermissionError: grpc.StatusCode.PERMISSION_DENIED,
            FileNotFoundError: grpc.StatusCode.NOT_FOUND,
            TimeoutError: grpc.StatusCode.DEADLINE_EXCEEDED,
            ConnectionError: grpc.StatusCode.UNAVAILABLE,
            NotImplementedError: grpc.StatusCode.UNIMPLEMENTED,
            OverflowError: grpc.StatusCode.OUT_OF_RANGE,
            ZeroDivisionError: grpc.StatusCode.INVALID_ARGUMENT,
            RuntimeError: grpc.StatusCode.INTERNAL,
        }

        for exc_type, code in mapping.items():
            if isinstance(exception, exc_type):
                return code

        return grpc.StatusCode.INTERNAL


def error_handler(method_name):
    """Decorator for comprehensive gRPC error handling."""

    def decorator(func):
        def wrapper(self, request, context):
            request_id = str(uuid.uuid4())
            self.state.register_request(request_id, method_name)

            # Add request ID to metadata
            context.set_trailing_metadata([
                ("x-request-id", request_id),
                ("x-service-name", "debug-grpc-service"),
            ])

            logger.info(f"[{request_id}] Starting {method_name}")

            try:
                result = func(self, request, context, request_id=request_id)
                logger.info(f"[{request_id}] Completed {method_name} successfully")
                return result

            except Exception as e:
                logger.error(
                    f"[{request_id}] Error in {method_name}: {type(e).__name__}: {e}",
                    exc_info=True,
                )

                self.state.register_error(str(e))

                # Serialize request data for debugging
                request_data = {}
                try:
                    for field in request.DESCRIPTOR.fields:
                        request_data[field.name] = getattr(request, field.name)
                except Exception:
                    request_data = {"raw": str(request)}

                # Build detailed error info
                error_details = ErrorContext.build_error_details(
                    exception=e,
                    method_name=method_name,
                    request_id=request_id,
                    service_state=self.state,
                    request_data=request_data,
                    additional_context={
                        "python_version": sys.version,
                        "pid": os.getpid(),
                        "peer": context.peer(),
                    },
                )

                grpc_code = ErrorContext.map_exception_to_grpc_code(e)

                context.set_code(grpc_code)
                context.set_details(error_details)

                logger.error(f"[{request_id}] Returning gRPC error: {grpc_code.name}")

                # Return empty/default response (gRPC will use the error status)
                context.abort(grpc_code, error_details)

            finally:
                self.state.complete_request(request_id)

        return wrapper

    return decorator


