class DataCorruptionError(Exception):
    """Custom exception for data integrity issues."""
    def __init__(self, entity, entity_id, details):
        self.entity = entity
        self.entity_id = entity_id
        self.details = details
        super().__init__(
            f"Data corruption detected in {entity} {entity_id}: {details}"
        )


